function _cancelOrder(address nftAddress, uint256 assetId) internal returns (Order memory) {
  address sender = _msgSender();
  Order memory order = orderByAssetId[nftAddress][assetId];

  require(order.id != 0, "MarketplaceV2#_cancelOrder: INVALID_ORDER");
  require(order.seller == sender || sender == owner(), "MarketplaceV2#_cancelOrder: UNAUTHORIZED_USER");

  bytes32 orderId = order.id;
  address orderSeller = order.seller;
  address orderNftAddress = order.nftAddress;
  delete orderByAssetId[nftAddress][assetId];

  emit OrderCancelled(
    orderId,
    assetId,
    orderSeller,
    orderNftAddress
  );

  return order;
}

function migrate(address _oldBurner) external {
    if (msg.sender != address(LIDO)) revert OnlyLidoCanMigrate();
    if (_oldBurner == address(0)) revert ZeroAddress("_oldBurner");
    _checkContractVersion(1);
    if (!_storageV3Upgrade().isMigrationAllowed) revert MigrationNotAllowedOrAlreadyMigrated();
    _storageV3Upgrade().isMigrationAllowed = false;

    IBurner oldBurner = IBurner(_oldBurner);
    Storage storage $ = _storage();
    $.totalCoverSharesBurnt = oldBurner.getCoverSharesBurnt();
    $.totalNonCoverSharesBurnt = oldBurner.getNonCoverSharesBurnt();
    (uint256 coverShares, uint256 nonCoverShares) = oldBurner.getSharesRequestedToBurn();
    $.coverSharesBurnRequested = coverShares;
    $.nonCoverSharesBurnRequested = nonCoverShares;
}

function _calculateFee() internal view returns (uint256 fee, int256 growth, uint256 abnormallyHighFeeThreshold) {
    VaultHub.Report memory report = latestReport();
    // we include quarantined value for fees as well
    uint256 quarantineValue = _lazyOracle().quarantineValue(address(_stakingVault()));
    uint256 totalValueAndQuarantine = uint256(report.totalValue) + quarantineValue;
    growth = int256(totalValueAndQuarantine) - report.inOutDelta;
    int256 unsettledGrowth = growth - settledGrowth;

    if (unsettledGrowth > 0) {
        fee = (uint256(unsettledGrowth) * feeRate) / TOTAL_BASIS_POINTS;
    }

    abnormallyHighFeeThreshold = (totalValueAndQuarantine * ABNORMALLY_HIGH_FEE_THRESHOLD_BP) / TOTAL_BASIS_POINTS;
}

function _postBurn(address owner, uint256[] calldata tokenIds, uint256[] calldata amounts) internal virtual {
    require(tokenIds.length > 0, "Invalid input");
    address extension = _tokensExtension[tokenIds[0]];
    for (uint256 i; i < tokenIds.length;) {
        require(_tokensExtension[tokenIds[i]] == extension, "Mismatched token originators");
        unchecked {
            ++i;
        }
    }
    // Callback to originating extension if needed
    if (extension != address(0)) {
        if (ERC165Checker.supportsInterface(extension, type(IERC1155CreatorExtensionBurnable).interfaceId)) {
            IERC1155CreatorExtensionBurnable(extension).onBurn(owner, tokenIds, amounts);
        }
    }
}

function _mintExtension(address to, string memory uri, uint80 data, uint256 tokenId)
        internal
        virtual
        returns (uint256)
    {
        if (tokenId == 0) {
            ++_tokenCount;
            tokenId = _tokenCount;
        }

        _checkMintPermissions(to, tokenId);
        // Call pre mint
        _preMintExtension(to, tokenId);

        _safeMint(to, tokenId, data << 16 | _extensionToIndex[msg.sender]);

        if (bytes(uri).length > 0) {
            _tokenURIs[tokenId] = uri;
        }

        return tokenId;
    }

function _approve(address to, uint256 tokenId, address auth, bool emitEvent) internal virtual {
    ERC721Storage storage $ = _getERC721Storage();
    // Avoid reading the owner unless necessary
    if (emitEvent || auth != address(0)) {
        address owner = _requireOwned(tokenId);

        // We do not use _isAuthorized because single-token approvals should not be able to call approve
        if (auth != address(0) && owner != auth && !isApprovedForAll(owner, auth)) {
            revert ERC721InvalidApprover(auth);
        }

        if (emitEvent) {
            emit Approval(owner, to, tokenId);
        }
    }

    $._tokenApprovals[tokenId] = to;
}

function _settleFeesFromHook(PoolKey calldata key, bytes32 positionKey)
        internal
        virtual
        returns (BalanceDelta withheldFees)
    {
        PoolId poolId = key.toId();

        withheldFees = getWithheldFees(poolId, positionKey);

        // Reset the `withheldFees`.
        _withheldFees[poolId][positionKey] = BalanceDeltaLibrary.ZERO_DELTA;

        // Settle the `withheldFees` for the liquidity position.
        if (withheldFees.amount0() > 0) {
            key.currency0.settle(poolManager, address(this), uint256(uint128(withheldFees.amount0())), true);
        }
        if (withheldFees.amount1() > 0) {
            key.currency1.settle(poolManager, address(this), uint256(uint128(withheldFees.amount1())), true);
        }
    }

function _beforeTokenTransfer(
    address operator,
    address from,
    address to,
    uint256[] memory ids,
    uint256[] memory amounts,
    bytes memory data
) internal virtual override {
    super._beforeTokenTransfer(operator, from, to, ids, amounts, data);

    if (from == address(0)) {
        for (uint256 i = 0; i < ids.length; ++i) {
            totalSupply[ids[i]] += amounts[i];
        }
    }

    if (to == address(0)) {
        for (uint256 i = 0; i < ids.length; ++i) {
            totalSupply[ids[i]] -= amounts[i];
        }
    }
}

function _depositRewardTokens(uint256 _amount) internal virtual {
    require(msg.sender == owner(), "Not authorized");

    address _rewardToken = rewardToken == CurrencyTransferLib.NATIVE_TOKEN ? nativeTokenWrapper : rewardToken;

    uint256 balanceBefore = IERC20(_rewardToken).balanceOf(address(this));
    CurrencyTransferLib.transferCurrencyWithWrapper(
        rewardToken,
        msg.sender,
        address(this),
        _amount,
        nativeTokenWrapper
    );
    uint256 actualAmount = IERC20(_rewardToken).balanceOf(address(this)) - balanceBefore;

    rewardTokenBalance += actualAmount;
}

function approveCurrencyForListing(
    uint256 _listingId,
    address _currency,
    uint256 _pricePerTokenInCurrency
) external onlyExistingListing(_listingId) onlyListingCreator(_listingId) {
    Listing memory listing = _directListingsStorage().listings[_listingId];
    require(
        _currency != listing.currency || _pricePerTokenInCurrency == listing.pricePerToken,
        "Marketplace: approving listing currency with different price."
    );
    require(
        _directListingsStorage().currencyPriceForListing[_listingId][_currency] != _pricePerTokenInCurrency,
        "Marketplace: price unchanged."
    );

    _directListingsStorage().currencyPriceForListing[_listingId][_currency] = _pricePerTokenInCurrency;

    emit CurrencyApprovedForListing(_listingId, _currency, _pricePerTokenInCurrency);
}

