function findLowerBound(uint256[] storage _array, uint256 _val) internal view returns (uint256) {
    uint256 len = _array.length;
    if (len == 0) {
        return 0;
    }

    if (_array[len - 1] <= _val) {
        return len - 1;
    }

    uint256 upperIdx = _array.findUpperBound(_val);

    // we already checked the last element above so the upper will always be inside the array
    assert(upperIdx < len);

    // the exact value we were searching is in the array
    if (_array[upperIdx] == _val) {
        return upperIdx;
    }

    // a 0 idx means that the first elem is already higher than the searched value (and not equal, checked above)
    if (upperIdx == 0) {
        return len;
    }

    // the element at upperIdx is the first element higher than the value we want, so return the previous element
    return upperIdx - 1;
}

function _countVote(
    uint256 _proposalId,
    address _account,
    uint8 _supportInt,
    uint256 _weight,
    bytes memory // params
) internal virtual override {
    if (_supportInt > uint8(VoteType.Abstain)) {
        revert InvalidVoteType(_supportInt);
    }
    VoteType support = VoteType(_supportInt);

    ProposalTally storage tally = _proposalTallies[_proposalId];
    ProposalVoterState storage voter = tally.voters[_account];

    if (voter.hasVoted) {
        revert VoteAlreadyCast();
    }
    voter.hasVoted = true;
    voter.support = support;

    _weight = _handleVoteOverrides(_proposalId, tally, voter, _account, _weight);

    if (support == VoteType.Against) {
        tally.againstVotes += _weight;
    } else if (support == VoteType.For) {
        tally.forVotes += _weight;
    } else {
        tally.abstainVotes += _weight;
    }
}

function _getCreatorRecipientAndCalculateFeeAmount(
    address collection,
    uint256 price,
    uint256[] memory itemIds
) private view returns (address creator, uint256 creatorFeeAmount) {
    if (address(creatorFeeManager) != address(0)) {
        (creator, creatorFeeAmount) = creatorFeeManager.viewCreatorFeeInfo(collection, price, itemIds);

        if (creator == address(0)) {
            // If recipient is null address, creator fee is set to 0
            creatorFeeAmount = 0;
        } else if (creatorFeeAmount * ONE_HUNDRED_PERCENT_IN_BP > (price * uint256(maxCreatorFeeBp))) {
            // If creator fee is higher than tolerated, it reverts
            revert CreatorFeeBpTooHigh();
        }
    }
}

function calculatePurchaseReturn(uint256 _supply, uint256 _connectorBalance, uint32 _connectorWeight, uint256 _depositAmount) public view returns (uint256) {
    // validate input
    require(_supply > 0 && _connectorBalance > 0 && _connectorWeight > 0 && _connectorWeight <= MAX_WEIGHT);

    // special case for 0 deposit amount
    if (_depositAmount == 0)
        return 0;

    // special case if the weight = 100%
    if (_connectorWeight == MAX_WEIGHT)
        return safeMul(_supply, _depositAmount) / _connectorBalance;

    uint256 result;
    uint8 precision;
    uint256 baseN = safeAdd(_depositAmount, _connectorBalance);
    (result, precision) = power(baseN, _connectorBalance, _connectorWeight, MAX_WEIGHT);
    uint256 temp = safeMul(_supply, result) >> precision;
    return temp - _supply;
}

function claimFailedDeposit(
    address _depositSender,
    address _l1Token,
    bytes32 _l2TxHash,
    uint256 _l2BatchNumber,
    uint256 _l2MessageIndex,
    uint16 _l2TxNumberInBatch,
    bytes32[] calldata _merkleProof
) external nonReentrant {
    uint256 amount = depositAmount[_depositSender][_l1Token][_l2TxHash];
    // empty deposit
    if (amount == 0) {
        revert EmptyDeposit();
    }
    delete depositAmount[_depositSender][_l1Token][_l2TxHash];

    L1_NULLIFIER.claimFailedDepositLegacyErc20Bridge({
        _depositSender: _depositSender,
        _l1Token: _l1Token,
        _amount: amount,
        _l2TxHash: _l2TxHash,
        _l2BatchNumber: _l2BatchNumber,
        _l2MessageIndex: _l2MessageIndex,
        _l2TxNumberInBatch: _l2TxNumberInBatch,
        _merkleProof: _merkleProof
    });
    emit ClaimedFailedDeposit(_depositSender, _l1Token, amount);
}

function _validateMethods(bytes calldata _terms, bytes calldata _executionCallData) private pure {
    (,, bytes calldata callData_) = _executionCallData.decodeSingle();

    require(callData_.length >= 4, "AllowedMethodsEnforcer:invalid-execution-data-length");

    bytes4 targetSig_ = bytes4(callData_[0:4]);
    bytes4[] memory allowedSignatures_ = getTermsInfo(_terms);
    uint256 allowedSignaturesLength_ = allowedSignatures_.length;

    for (uint256 i = 0; i < allowedSignaturesLength_; ++i) {
        if (targetSig_ == allowedSignatures_[i]) {
            return;
        }
    }
    revert("AllowedMethodsEnforcer:method-not-allowed");
}

function getAddressNFTs(address userAddress) public view override returns (uint256[] memory NFTs, uint256 numberOfActive) {

    uint256 numberOfTokens = balanceOf(userAddress);

    numberOfActive = 0;
    uint256[] memory temp = new uint256[](numberOfTokens);
    for (uint256 x = 0; x < numberOfTokens; x++) {
        if (!accountLiquidated(tokenOfOwnerByIndex(userAddress, x))) {
            temp[numberOfActive] = tokenOfOwnerByIndex(userAddress, x);
            numberOfActive++;
        }
    }

    NFTs = new uint256[](numberOfActive);
    for (uint256 x = 0; x < numberOfActive; x++) {
        NFTs[x] = temp[x];
    }

    return (NFTs, numberOfActive);
}

function _setMarketBorrowCaps(
    MToken[] calldata mTokens,
    uint[] calldata newBorrowCaps
) external {
    require(
        msg.sender == admin || msg.sender == borrowCapGuardian,
        "only admin or borrow cap guardian can set borrow caps"
    );

    uint numMarkets = mTokens.length;
    uint numBorrowCaps = newBorrowCaps.length;

    require(
        numMarkets != 0 && numMarkets == numBorrowCaps,
        "invalid input"
    );

    for (uint i = 0; i < numMarkets; i++) {
        borrowCaps[address(mTokens[i])] = newBorrowCaps[i];
        emit NewBorrowCap(mTokens[i], newBorrowCaps[i]);
    }
}

constructor(
    address _inbox,
    address _checkpointTracker,
    address _initialProver,
    uint96 _initialFee,
    uint256 _initialDeposit
) {
    require(_inbox != address(0), ZeroAddress());
    require(_checkpointTracker != address(0), ZeroAddress());
    require(_initialProver != address(0), ZeroAddress());

    inbox = IInbox(_inbox);
    checkpointTracker = ICheckpointTracker(_checkpointTracker);

    // Close the first period so every period has a previous one (and an implicit start timestamp)
    // The initial fee and prover will take effect in the block after this one
    _deposit(_initialProver, _initialDeposit);
    _claimProvingVacancy(_initialFee, _initialProver);
}

function _requestRedeem(
    uint256 shares,
    address controller,
    address owner,
    uint256 requestId
) internal virtual returns (uint256) {
    require(_isRedeemAsync(), ERC7540SyncRedeem());

    address sender = _msgSender();
    if (owner != sender && !isOperator(owner, sender)) {
        _spendAllowance(owner, sender, shares);
    }
    if (_redeemShareDestination() == address(0)) {
        _totalPendingRedeemShares += shares;
        _burn(owner, shares);
    } else {
        _transfer(owner, _redeemShareDestination(), shares);
    }

    emit RedeemRequest(controller, owner, requestId, _msgSender(), shares);
    return requestId;
}

constructor(IERC7984ERC20Wrapper fromToken_, IERC7984ERC20Wrapper toToken_) {
    require(
        ERC165Checker.supportsInterface(address(fromToken_), type(IERC7984ERC20Wrapper).interfaceId),
        InvalidWrapperToken(address(fromToken_))
    );
    require(
        ERC165Checker.supportsInterface(address(toToken_), type(IERC7984ERC20Wrapper).interfaceId),
        InvalidWrapperToken(address(toToken_))
    );
    require(fromToken_.underlying() != toToken_.underlying(), DuplicateUnderlyingTokens());

    _fromToken = fromToken_;
    _toToken = toToken_;
    _currentBatchId = 1;

    SafeERC20.forceApprove(IERC20(fromToken().underlying()), address(fromToken()), type(uint256).max);
    SafeERC20.forceApprove(IERC20(toToken().underlying()), address(toToken()), type(uint256).max);
}

function _moveDelegateVotes(address from, address to, euint64 amount) internal virtual {
    CheckpointsConfidential.TraceEuint64 storage store;
    if (from != to && FHE.isInitialized(amount)) {
        if (from != address(0)) {
            store = _delegateCheckpoints[from];
            euint64 newValue = store.latest().sub(amount);
            newValue.allowThis();
            euint64 oldValue = _push(store, newValue);
            emit DelegateVotesChanged(from, oldValue, newValue);
        }
        if (to != address(0)) {
            store = _delegateCheckpoints[to];
            euint64 newValue = store.latest().add(amount);
            newValue.allowThis();
            euint64 oldValue = _push(store, newValue);
            emit DelegateVotesChanged(to, oldValue, newValue);
        }
    }
}

function createOfferMinimal(address _tokenContract, uint256 _tokenId) external payable nonReentrant returns (uint256) {
    uint256 _offerAmount = msg.value;
    weth.deposit{value: msg.value}();
    weth.transferFrom(address(this), msg.sender, _offerAmount);

    if (weth.allowance(msg.sender, address(erc20TransferHelper)) < _offerAmount) revert INSUFFICIENT_ALLOWANCE();
    if (!erc721TransferHelper.isModuleApproved(msg.sender)) revert MODULE_NOT_APPROVED();

    ++offerCount;

    StoredOffer storage offer = offers[_tokenContract][_tokenId][offerCount];
    offer.amount = _offerAmount;
    offer.maker = msg.sender;
    offer.features = 0;

    offersForNFT[_tokenContract][_tokenId].push(offerCount);
    emit OfferCreated(_tokenContract, _tokenId, offerCount, _getFullOffer(offer));
    return offerCount;
}

function _remove(
    _PackedDoublyLinkedList storage self,
    bytes16 value
) private returns (bool status) {
    if (_contains(self, value)) {
        (bytes16 prevValue, bytes16 nextValue) = _adjacent(self, value);

        bytes32 prevLinks = self._links[prevValue];
        self._links[prevValue] =
            (prevLinks & MASK_PREV) | _formatLinks(0, nextValue);

        bytes32 nextLinks = self._links[nextValue];
        self._links[nextValue] =
            (nextLinks & MASK_NEXT) | _formatLinks(prevValue, 0);

        delete self._links[value];
        status = true;
    }
}

function executeHotfix(
  uint256[] calldata values,
  address[] calldata destinations,
  bytes calldata data,
  uint256[] calldata dataLengths,
  bytes32 salt
) external {
  bytes32 hash = keccak256(abi.encode(values, destinations, data, dataLengths, salt));

  (
    bool approved,
    bool councilApproved,
    bool executed,
    uint256 executionTimeLimit
  ) = getHotfixRecord(hash);
  require(!executed, "hotfix already executed");
  require(approved, "hotfix not approved");
  require(councilApproved, "hotfix not approved by security council");
  require(executionTimeLimit >= now, "Execution time limit has already been reached.");
  Proposals.makeMem(values, destinations, data, dataLengths, msg.sender, 0).executeMem();

  hotfixes[hash].executed = true;
  emit HotfixExecuted(hash);
}

function getPendingWithdrawalsInBatch(
  address account,
  uint256 from,
  uint256 to
) public view returns (uint256[] memory, uint256[] memory) {
  uint256 pendingWithdrawalsLength = getTotalPendingWithdrawalsCount(account);

  if (pendingWithdrawalsLength == 0) {
    return (new uint256[](0), new uint256[](0));
  }
  require(from <= to, "Invalid range");
  uint256 _to = Math.min(to, pendingWithdrawalsLength - 1);
  uint256 length = _to - from + 1;
  uint256[] memory values = new uint256[](length);
  uint256[] memory timestamps = new uint256[](length);
  for (uint256 i = from; i <= _to; i = i.add(1)) {
    PendingWithdrawal memory pendingWithdrawal = balances[account].pendingWithdrawals[i];
    values[i - from] = pendingWithdrawal.value;
    timestamps[i - from] = pendingWithdrawal.timestamp;
  }
  return (values, timestamps);
}

function getSupportWithQuorumPadding(
  Proposal storage proposal,
  FixidityLib.Fraction memory quorum
) internal view returns (FixidityLib.Fraction memory) {
  uint256 yesVotes = proposal.votes.yes;
  if (yesVotes == 0) {
    return FixidityLib.newFixed(0);
  }
  uint256 noVotes = proposal.votes.no;
  uint256 totalVotes = yesVotes.add(noVotes).add(proposal.votes.abstain);
  uint256 requiredVotes = quorum
    .multiply(FixidityLib.newFixed(proposal.networkWeight))
    .fromFixed();
  if (requiredVotes > totalVotes) {
    noVotes = noVotes.add(requiredVotes.sub(totalVotes));
  }
  return FixidityLib.newFixedFraction(yesVotes, yesVotes.add(noVotes));
}

function isValidZKEmail(
    EmailProof memory emailProof,
    IDKIMRegistry dkimregistry,
    IGroth16Verifier groth16Verifier,
    bytes32 hash
) internal view returns (EmailProofError) {
    string[] memory signHashTemplate = new string[](2);
    signHashTemplate[0] = "signHash";
    signHashTemplate[1] = CommandUtils.UINT_MATCHER; // UINT_MATCHER is always lowercase
    bytes[] memory signHashParams = new bytes[](1);
    signHashParams[0] = abi.encode(hash);
    return
        isValidZKEmail(emailProof, dkimregistry, groth16Verifier, signHashTemplate, signHashParams, Case.LOWERCASE);
}

function buildGetApprovalProcessCommand(string memory command) internal view returns (string[] memory) {
    string[] memory inputBuilder = new string[](255);

    uint8 i = 0;

    inputBuilder[i++] = "npx";
    inputBuilder[i++] = string(
        abi.encodePacked("@openzeppelin/defender-deploy-client-cli@", Versions.DEFENDER_DEPLOY_CLIENT_CLI)
    );
    inputBuilder[i++] = command;
    inputBuilder[i++] = "--chainId";
    inputBuilder[i++] = Strings.toString(block.chainid);

    // Create a copy of inputs but with the correct length
    string[] memory inputs = new string[](i);
    for (uint8 j = 0; j < i; j++) {
        inputs[j] = inputBuilder[j];
    }

    return inputs;
}

constructor(
    uint80 _timeUnit,
    address _defaultAdmin,
    uint256 _rewardRatioNumerator,
    uint256 _rewardRatioDenominator,
    address _stakingToken,
    address _rewardToken,
    address _nativeTokenWrapper
)
    Staking20(
        _nativeTokenWrapper,
        _stakingToken,
        IERC20Metadata(_stakingToken).decimals(),
        IERC20Metadata(_rewardToken).decimals()
    )
{
    _setupOwner(_defaultAdmin);
    _setStakingCondition(_timeUnit, _rewardRatioNumerator, _rewardRatioDenominator);

    require(_rewardToken != _stakingToken, "Reward Token and Staking Token can't be same.");
    rewardToken = _rewardToken;
}

