function getElements(
  SortedLinkedListWithMedian.List storage list
)
  public
  view
  returns (address[] memory, uint256[] memory, SortedLinkedListWithMedian.MedianRelation[] memory)
{
  bytes32[] memory byteKeys = list.getKeys();
  address[] memory keys = new address[](byteKeys.length);
  uint256[] memory values = new uint256[](byteKeys.length);
  // prettier-ignore
  SortedLinkedListWithMedian.MedianRelation[] memory relations =
    new SortedLinkedListWithMedian.MedianRelation[](keys.length);
  for (uint256 i = 0; i < byteKeys.length; i = i.add(1)) {
    keys[i] = toAddress(byteKeys[i]);
    values[i] = list.getValue(byteKeys[i]);
    relations[i] = list.relation[byteKeys[i]];
  }
  return (keys, values, relations);
}

function getTransactionIds(
  uint256 from,
  uint256 to,
  bool pending,
  bool executed
) external view returns (uint256[] memory _transactionIds) {
  uint256[] memory transactionIdsTemp = new uint256[](transactionCount);
  uint256 count = 0;
  uint256 i;
  for (i = 0; i < transactionCount; i = i.add(1))
    if ((pending && !transactions[i].executed) || (executed && transactions[i].executed)) {
      transactionIdsTemp[count] = i;
      count = count.add(1);
    }
  _transactionIds = new uint256[](to.sub(from));
  for (i = from; i < to; i = i.add(1)) _transactionIds[i.sub(from)] = transactionIdsTemp[i];
}

function batchlookupAccountsForIdentifier(
  bytes32[] memory identifiersToLookup
) internal view returns (uint256[] memory, address[] memory) {
  require(identifiersToLookup.length > 0, "You have to pass at least one identifier");
  uint256 totalAddresses = 0;
  uint256[] memory matches = new uint256[](identifiersToLookup.length);

  for (uint256 i = 0; i < identifiersToLookup.length; i = i.add(1)) {
    uint256 count = identifiers[identifiersToLookup[i]].accounts.length;

    totalAddresses = totalAddresses.add(count);
    matches[i] = count;
  }

  return (matches, new address[](totalAddresses));
}

function batchGetMetadataURL(
  address[] calldata accountsToQuery
) external view returns (uint256[] memory, bytes memory) {
  uint256 totalSize = 0;
  uint256[] memory sizes = new uint256[](accountsToQuery.length);
  for (uint256 i = 0; i < accountsToQuery.length; i = i.add(1)) {
    sizes[i] = bytes(accounts[accountsToQuery[i]].metadataURL).length;
    totalSize = totalSize.add(sizes[i]);
  }

  bytes memory data = new bytes(totalSize);
  uint256 pointer = 0;
  for (uint256 i = 0; i < accountsToQuery.length; i = i.add(1)) {
    for (uint256 j = 0; j < sizes[i]; j = j.add(1)) {
      data[pointer] = bytes(accounts[accountsToQuery[i]].metadataURL)[j];
      pointer = pointer.add(1);
    }
  }
  return (sizes, data);
}

function getOffchainStorageRoots(
  address account
) external view returns (bytes memory, uint256[] memory) {
  require(isAccount(account), "Unknown account");
  uint256 numberRoots = offchainStorageRoots[account].length;
  uint256 totalLength = 0;
  for (uint256 i = 0; i < numberRoots; i++) {
    totalLength = totalLength.add(offchainStorageRoots[account][i].length);
  }

  bytes memory concatenated = new bytes(totalLength);
  uint256 lastIndex = 0;
  uint256[] memory lengths = new uint256[](numberRoots);
  for (uint256 i = 0; i < numberRoots; i++) {
    bytes storage root = offchainStorageRoots[account][i];
    lengths[i] = root.length;
    for (uint256 j = 0; j < lengths[i]; j++) {
      concatenated[lastIndex] = root[j];
      lastIndex++;
    }
  }

  return (concatenated, lengths);
}

